#### 任务 1.1: 实现迭代管理 API

**目标**: 提供完整的迭代 CRUD 接口

**实现内容**:

```typescript
// routes/iterations.ts
export async function iterationRoutes(fastify: FastifyInstance, options: RouteOptions) {
  const { iterationService } = options;

  // 获取迭代列表（分页 + 筛选）
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status, startDate, endDate } = request.query as any;

    const result = await iterationService.list({
      page: parseInt(page),
      limit: parseInt(limit),
      filter: { status, startDate, endDate }
    });

    return reply.send(result);
  });

  // 获取迭代详情
  fastify.get<{ Params: { id: string } }>('/iterations/:id', async (request, reply) => {
    const { id } = request.params;
    const detail = await iterationService.getDetail(parseInt(id));
    return reply.send(detail);
  });

  // 获取当前运行迭代
  fastify.get('/iterations/current', async (request, reply) => {
    const current = await iterationService.getCurrent();
    return reply.send(current);
  });

  // 回滚到指定迭代
  fastify.post<{ Params: { id: string } }>('/iterations/:id/rollback', async (request, reply) => {
    const { id } = request.params;
    const result = await iterationService.rollback(parseInt(id));
    return reply.send(result);
  });

  // 对比两个迭代
  fastify.get('/iterations/:id1/diff/:id2', async (request, reply) => {
    const { id1, id2 } = request.params;
    const diff = await iterationService.diff(parseInt(id1), parseInt(id2));
    return reply.send(diff);
  });
}
```

**验收标准**:
- ✅ 所有 API 端点可访问
- ✅ 分页功能正常
- ✅ 筛选功能正常（状态、时间范围）
- ✅ API 响应时间 < 100ms

