// routes/agents.ts
export async function agentRoutes(fastify: FastifyInstance, options: RouteOptions) {
  const { agentService } = options;

  // 获取所有 Agent 状态
  fastify.get('/agents', async (request, reply) => {
    const agents = await agentService.getAllStates();
    return reply.send(agents);
  });

  // 获取特定 Agent 状态
  fastify.get<{ Params: { name: string } }>('/agents/:name', async (request, reply) => {
    const { name } = request.params;
    const agent = await agentService.getState(name);
    return reply.send(agent);
  });

  // 获取 Agent 性能统计
  fastify.get<{ Params: { name: string } }>('/agents/:name/stats', async (request, reply) => {
    const { name } = request.params;
    const stats = await agentService.getPerformanceStats(name);
    return reply.send(stats);
  });

  // 获取 Agent 执行历史
  fastify.get('/agents/history', async (request, reply) => {
    const { limit = 50 } = request.query as any;
    const history = await agentService.getExecutionHistory(parseInt(limit));
    return reply.send(history);
  });
}
```

**验收标准**:
