#### 任务 2.1: 增强 RealtimeService

**目标**: 完善实时事件广播机制

**实现内容**:

```typescript
// services/realtime.service.ts
export class RealtimeService {
  private clients: Set<WebSocket> = new Set();
  private subscriptions: Map<WebSocket, Set<string>> = new Map();

  // 广播迭代状态变化
  broadcastIterationStatus(data: IterationStatusChange) {
    this.broadcast({
      event: 'iteration.status_changed',
      data
    });
  }

  // 广播 Agent 状态变化
  broadcastAgentStatus(data: AgentStatusChange) {
    this.broadcast({
      event: 'agent.status_changed',
      data
    });
  }

  // 广播迭代进度
  broadcastProgress(data: IterationProgress) {
    this.broadcast({
      event: 'iteration.progress',
      data
    });
  }

  // 广播系统指标
  broadcastMetrics(data: SystemMetricsEvent) {
    this.broadcast({
      event: 'system.metrics',
      data
    });
  }

  // 广播日志条目
  broadcastLog(data: LogEntry) {
    this.broadcast({
      event: 'log.entry',
      data
    });
  }

  private broadcast(message: any) {
    const payload = JSON.stringify(message);
    this.clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(payload);
      }
    });
  }
}
