#### 任务 2.2: AutoIterationEngine 集成

**目标**: 将迭代过程实时推送到 Dashboard

**实现内容**:

```typescript
// auto-iteration.ts
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private realtimeService?: RealtimeService;
  private iterationService?: IterationService;

  async initialize() {
    const services = getServices();
    this.realtimeService = services.realtimeService;
    this.iterationService = services.iterationService;
  }

  async startIteration() {
    // 创建迭代记录
    const iteration = await this.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement: this.requirement,
      startedAt: new Date()
    });

    // 广播迭代开始
    this.realtimeService.broadcastIterationStatus({
      iterationId: iteration.id,
      iterationNumber: this.count,
      status: 'running',
      timestamp: new Date()
    });

    // 执行产品经理 Agent
    await this.runAgent('product-manager', async () => {
      this.realtimeService.broadcastAgentStatus({
        iterationId: iteration.id,
        agentName: '产品经理',
        agentType: 'product-manager',
        status: 'running',
        progress: 0,
        timestamp: new Date()
      });

      const result = await this.productManagerAgent.run(this.requirement);

      this.realtimeService.broadcastAgentStatus({
        iterationId: iteration.id,
        agentName: '产品经理',
        agentType: 'product-manager',
        status: 'completed',
        progress: 100,
        output: result.output,
        timestamp: new Date()
      });

      return result;
    });

    // 执行其他 Agent...
  }

  private async runAgent(agentName: string, fn: Function) {
    // 广播 Agent 开始执行
    this.realtimeService.broadcastProgress({
      iterationId: this.currentIterationId,
      phase: agentName,
      progress: 0,
      message: `${agentName} 开始执行...`,
      timestamp: new Date()
    });

    try {
      const result = await fn();

      // 广播进度更新
      this.realtimeService.broadcastProgress({
        iterationId: this.currentIterationId,
        phase: agentName,
        progress: 100,
        message: `${agentName} 执行完成`,
        timestamp: new Date()
      });

      return result;
    } catch (error) {
      // 广播错误
      this.realtimeService.broadcastLog({
        timestamp: new Date(),
        level: 'error',
        message: `${agentName} 执行失败: ${error.message}`,
        context: { agentName, error }
      });

      throw error;
    }
  }
}
```

