<script setup lang="ts">
import { ref, computed, watch, nextTick } from 'vue';
import { useWebSocketStore } from '@/stores/websocket';
import { format } from 'date-fns';

const wsStore = useWebSocketStore();
const logContainer = ref<HTMLElement>();
const autoScroll = ref(true);

const filters = ref({
  level: 'all',
  keyword: ''
});

const logs = ref<LogEntry[]>([]);

// 监听 WebSocket 日志事件
wsStore.on('log.entry', (data: LogEntry) => {
  logs.value.push(data);

  // 限制最大行数
  if (logs.value.length > 1000) {
    logs.value = logs.value.slice(-1000);
  }

  // 自动滚动
  if (autoScroll.value) {
    nextTick(() => {
      if (logContainer.value) {
        logContainer.value.scrollTop = logContainer.value.scrollHeight;
      }
    });
  }
});

const filteredLogs = computed(() => {
  return logs.value.filter(log => {
    if (filters.value.level !== 'all' && log.level !== filters.value.level) {
      return false;
    }
    if (filters.value.keyword && !log.message.includes(filters.value.keyword)) {
      return false;
    }
    return true;
  });
});

function formatTime(date: Date) {
  return format(date, 'HH:mm:ss.SSS');
}

function handleExport() {
  const text = filteredLogs.value.map(log => {
    return `[${log.level.toUpperCase()}] ${formatTime(log.timestamp)} ${log.message}`;
  }).join('\n');

  const blob = new Blob([text], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `logs-${Date.now()}.txt`;
  a.click();
}

function handleClear() {
  logs.value = [];
}
</script>

